<template><div class="smart-job-page"><section class="page-header"><div><p class="eyebrow">Learning Path</p><h2>Personalized Learning Resource Recommendation</h2><p>Combines direction, difficulty, goals, and skills to match learning resources and paths.</p></div></section><section class="workspace"><aside class="profile-panel"><div class="panel-title"><h3>Learning Profile</h3></div><div class="form-grid"><label class="field"><span>City</span><el-input v-model="params.city" placeholder="e.g. Shanghai"></el-input></label><label class="field"><span>Direction</span><el-input v-model="params.position" placeholder="e.g. AI"></el-input></label></div></aside><div class="results-panel"><div v-if="sampleJobs.length"><el-card v-for="j in sampleJobs" :key="j.id"><h4>{{j.title}}</h4><p>{{j.company}} | {{j.city}} | Score: {{Math.round(j.matchScore)}}%</p></el-card></div></div></section><div class="chat-panel"><h3>AI Path Advisor</h3><div v-for="m in pathMessages" :key="m.id" v-html="sanitizeHtml(m.content)"></div><el-input v-model="pathInput" placeholder="Ask learning path..."></el-input><el-button @click="sendPathMessage()">Send</el-button></div></div></template><script>import axios from 'axios';import DOMPurify from 'dompurify';export default{name:'LearningPath',data(){return{params:{city:'',position:''},sampleJobs:[{id:1,title:'AI Foundations',company:'SmartEdu',city:'Online',matchScore:92},{id:2,title:'Python Programming',company:'Runoob',city:'Online',matchScore:88}],pathMessages:[],pathInput:'',loading:false}},methods:{sanitizeHtml(h){return h?DOMPurify.sanitize(h):''},async sendPathMessage(){if(!this.pathInput||this.loading)return;const msg=this.pathInput;this.pathInput='';this.pathMessages.push({id:Date.now(),role:'user',content:msg});this.loading=true;try{const r=await axios.post('/api/learning-agent/chat',{agentType:'path',message:msg});this.pathMessages.push({id:Date.now(),role:'assistant',content:r.data.content,mode:r.data.mode})}catch(e){this.pathMessages.push({id:Date.now(),role:'assistant',content:'Path agent unavailable'})}this.loading=false}}}</script>